+/* =============================================================================
+   MOBILE SCROLL LOCK - Prevent accidental horizontal scrolling
+   These rules are CRITICAL for proper mobile UX. Applied globally, not just iOS.
+   ============================================================================= */
+
+html {
+  /* Prevent horizontal scroll on the root */
+  overflow-x: hidden;
+  /* Prevent horizontal overscroll bounce */
+  overscroll-behavior-x: none;
+  /* touch-action: manipulation prevents 300ms tap delay and double-tap zoom */
+  touch-action: manipulation;
+}
+
+body {
+  /* Prevent horizontal scroll - belt and suspenders */
+  overflow-x: hidden;
+  /* Constrain width to viewport */
+  max-width: 100vw;
+  /* Prevent horizontal overscroll bounce */
+  overscroll-behavior-x: none;
+}
+
